   823→#ifdef DEBUG_NODE_TESTS_ENABLED
   824→
   825→	/* Optional debugging check: pass querytree through copyObject() */
   826→	if (Debug_copy_parse_plan_trees)
   827→	{
   828→		List	   *new_list;
   829→
   830→		new_list = copyObject(querytree_list);
